select *
from batch.job_definition
where tenant_id = #{tenantId}

    and job_code like concat('%', #{jobCode}, '%')


    and job_name like concat('%', #{jobName}, '%')


    and job_type = #{jobType}


    and worker_group like concat('%', #{workerGroup}, '%')


    and queue_code like concat('%', #{queueCode}, '%')


    and schedule_type = #{scheduleType}


    and enabled = #{enabled}

order by id desc

select count(1)
from batch.job_definition
where tenant_id = #{tenantId}

    and job_code like concat('%', #{jobCode}, '%')


    and job_name like concat('%', #{jobName}, '%')


    and job_type = #{jobType}


    and worker_group like concat('%', #{workerGroup}, '%')


    and queue_code like concat('%', #{queueCode}, '%')


    and schedule_type = #{scheduleType}


    and enabled = #{enabled}

select *
from batch.job_definition
where tenant_id = #{tenantId}
  and job_code = #{jobCode}

